/**
 * @summary Get expense records with optional filters
 */
export const getGetGastosUrl = (params?: GetGastosParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/gastos?${stringifiedParams}`
    : `/api/gastos`;
};

export const getGastos = async (
  params?: GetGastosParams,
  options?: RequestInit,
): Promise<GastosResponse> => {
  return customFetch<GastosResponse>(getGetGastosUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetGastosQueryKey = (params?: GetGastosParams) => {
  return [`/api/gastos`, ...(params ? [params] : [])] as const;
};

export const getGetGastosQueryOptions = <
  TData = Awaited<ReturnType<typeof getGastos>>,
  TError = ErrorType<unknown>,
>(
  params?: GetGastosParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getGastos>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetGastosQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getGastos>>> = ({
    signal,
  }) => getGastos(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getGastos>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetGastosQueryResult = NonNullable<
  Awaited<ReturnType<typeof getGastos>>
>;
export type GetGastosQueryError = ErrorType<unknown>;

/**
 * @summary Get expense records with optional filters
 */

